-- Seed public.fixtures from openfootball (generated 2026-06-12T15:37:45.877Z).
-- Run in the Supabase SQL editor. Idempotent: re-running refreshes kickoff/result.
-- The sync-fixtures Edge Function does the same on a schedule once deployed.

on conflict (match_key) do update set
  team1=excluded.team1, team2=excluded.team2, kickoff_utc=excluded.kickoff_utc,
  round=excluded.round, grp=excluded.grp, result=excluded.result, ft=excluded.ft,
  updated_at=now();
